import React, { useEffect, useState } from 'react';
import { View, Text, TouchableOpacity, StyleSheet, ScrollView, Alert, Button } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

export default function HomeScreen({ navigation }) {
  const [userData, setUserData] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const d = await AsyncStorage.getItem('userData');
        if (d) setUserData(JSON.parse(d));
      } catch (e) {}
    })();
  }, []);

  const handleLogout = async () => {
    Alert.alert('Déconnexion', 'Voulez-vous vraiment vous déconnecter ?', [
      { text: 'Annuler', style: 'cancel' },
      { text: 'Oui', onPress: async () => {
          await AsyncStorage.removeItem('authToken');
          await AsyncStorage.removeItem('userData');
          navigation.replace('Login');
        }
      }
    ]);
  };

  const MenuCard = ({ title, screen, color = '#0d6efd', sub }) => (
    <TouchableOpacity 
      style={[styles.menuCard, { backgroundColor: color || '#fff' }]} 
      onPress={() => navigation.navigate(screen)}
    >
      <Text style={[styles.cardTitle, { color: color ? '#fff' : '#333' }]}>{title}</Text>
      {sub && <Text style={[styles.cardSub, { color: color ? '#eee' : '#666' }]}>{sub}</Text>}
    </TouchableOpacity>
  );

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <Text style={styles.title}>ATELIKO MOBILE</Text>
      <Text style={styles.hello}>Bonjour, {userData?.prenom || 'Utilisateur'}</Text>

      <View style={styles.grid}>
        <View style={styles.row}>
          <MenuCard title="NOUVELLE MESURE" screen="MesureAdd" color="#20c997" sub="Ajouter Client & Mesures" />
        </View>
        <View style={styles.row}>
          <MenuCard title="CLIENTS" screen="Clients" color="#0dcaf0" sub="Liste des clients" />
          <MenuCard title="RENDEZ-VOUS" screen="Rendezvous" color="#ffc107" sub="Planning" />
        </View>
        <View style={styles.row}>
          <MenuCard title="PAIEMENTS" screen="Paiements" color="#6610f2" sub="Gestion caisse" />
          <MenuCard title="ABONNEMENT" screen="Abonnement" color="#fd7e14" sub="Formule & Renouvellement" />
        </View>
        <View style={styles.row}>
          <MenuCard title="MON PROFIL" screen="Profile" color="#adb5bd" sub="Modifier photo" />
        </View>
      </View>

      <View style={{marginTop: 32}}>
        <Button title="Se déconnecter" onPress={handleLogout} color="#dc3545" />
      </View>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: { flexGrow: 1, padding: 16, backgroundColor: '#f8f9fa' },
  title: { fontSize: 24, fontWeight: 'bold', textAlign: 'center', marginBottom: 8, color: '#333' },
  hello: { fontSize: 16, textAlign: 'center', marginBottom: 24, color: '#666' },
  grid: { gap: 16 },
  row: { flexDirection: 'row', gap: 12 },
  menuCard: { flex: 1, padding: 20, borderRadius: 12, elevation: 3, minHeight: 100, justifyContent: 'center' },
  cardTitle: { fontSize: 16, fontWeight: 'bold', textAlign: 'center', textTransform: 'uppercase' },
  cardSub: { fontSize: 12, textAlign: 'center', marginTop: 4 }
});
